// Optional xüsusiyyətlərin sintaksisi
interface Person {
  name: string;
  age?: number;
}

let person1: Person = { name: 'Ali' };
let person2: Person = { name: 'Vəli', age: 25 };

console.log(person1); // { name: 'Ali' }
console.log(person2); // { name: 'Vəli', age: 25 }
// let invalid: Person = { age: 30 }; // Xəta: name xüsusiyyəti yoxdur

// Optional xüsusiyyətlər ilə tip aliasları
type Id = number | string;

interface User {
  id: Id;
  name: string;
  email?: string;
}

let user1: User = { id: 1, name: 'Ali' };
let user2: User = { id: 'abc', name: 'Vəli', email: 'veli@example.com' };

console.log(user1); // { id: 1, name: 'Ali' }
console.log(user2); // { id: 'abc', name: 'Vəli', email: 'veli@example.com' }
// let invalid: User = { id: 2 }; // Xəta: name xüsusiyyəti yoxdur

// Optional xüsusiyyətlər siniflərdə
interface Person {
  name: string;
  age?: number;
}

class Employee implements Person {
  name: string;
  age?: number;

  constructor(name: string, age?: number) {
    this.name = name;
    this.age = age;
  }
}

let employee1 = new Employee('Ali');
let employee2 = new Employee('Vəli', 30);

console.log(employee1); // Employee { name: 'Ali' }
console.log(employee2); // Employee { name: 'Vəli', age: 30 }

// Funksiyalarda optional xüsusiyyətlər
interface User {
  name: string;
  email?: string;
}

function printUser(user: User): string {
  return user.email ? `${user.name} (${user.email})` : user.name;
}

let user1: User = { name: 'Ali' };
let user2: User = { name: 'Vəli', email: 'veli@example.com' };

console.log(printUser(user1)); // Ali
console.log(printUser(user2)); // Vəli (veli@example.com)

// Optional parametrlər ilə optional xüsusiyyətlər
interface Product {
  name: string;
  price?: number;
}

function createProduct(name: string, price?: number): Product {
  return { name, price };
}

let product1 = createProduct('Phone');
let product2 = createProduct('Laptop', 1000);

console.log(product1); // { name: 'Phone' }
console.log(product2); // { name: 'Laptop', price: 1000 }

// Praktik nümunə
interface Order {
  id: number;
  product: string;
  quantity?: number;
}

function processOrder(order: Order): string {
  const qty = order.quantity ?? 1;
  return `Order ${order.id}: ${order.product} (Qty: ${qty})`;
}

let order1: Order = { id: 1, product: 'Phone' };
let order2: Order = { id: 2, product: 'Laptop', quantity: 3 };

console.log(processOrder(order1)); // Order 1: Phone (Qty: 1)
console.log(processOrder(order2)); // Order 2: Laptop (Qty: 3)

// Təhlükəsizlik nümunəsi
interface User {
  name: string;
  email?: string;
}

function getUserInfo(user: User): string {
  return user.email ? `${user.name} (${user.email})` : user.name;
}

let user: User = { name: 'Ali' };
console.log(getUserInfo(user)); // Ali
// let invalid: User = { email: 'ali@example.com' }; // Xəta: name yoxdur

// Səhvə yol açan nümunə
let unsafe: any = { name: 'Ali', email: 'ali@example.com' };
console.log(unsafe.name, unsafe.email); // Ali, ali@example.com, lakin tip təhlükəsizliyi yoxdur
unsafe = { name: 'Vəli' };
console.log(unsafe.name, unsafe.email); // Vəli, undefined, runtime xətası ola bilər

// Düzgün yol
interface User {
  name: string;
  email?: string;
}

let user: User = { name: 'Ali', email: 'ali@example.com' };
console.log(user.name, user.email ?? 'No email'); // Ali, ali@example.com
let user2: User = { name: 'Vəli' };
console.log(user2.name, user2.email ?? 'No email'); // Vəli, No email

// Real layihə ssenarisi
interface UserProfile {
  id: number;
  username: string;
  bio?: string;
  avatarUrl?: string;
}

function displayProfile(profile: UserProfile): string {
  let result = `User: ${profile.username} (ID: ${profile.id})`;
  if (profile.bio) result += `, Bio: ${profile.bio}`;
  if (profile.avatarUrl) result += `, Avatar: ${profile.avatarUrl}`;
  return result;
}

let profile1: UserProfile = { id: 1, username: 'ali123' };
let profile2: UserProfile = { id: 2, username: 'veli456', bio: 'Developer', avatarUrl: 'avatar.png' };

console.log(displayProfile(profile1)); // User: ali123 (ID: 1)
console.log(displayProfile(profile2)); // User: veli456 (ID: 2), Bio: Developer, Avatar: avatar.png

