  name: string;
  age?: number;
}

class Employee implements Person {
  name: string;
  age?: number;

  constructor(name: string, age?: number) {
    this.name = name;
    this.age = age;
  }
}

let employee1 = new Employee('Алиса');
let employee2 = new Employee('Боб', 30);

